# ---- Environment Detection ----


def detect_display_server() -> str:
    """Detect whether we're on Wayland, X11, or unknown."""
    session_type = os.environ.get("XDG_SESSION_TYPE", "")
    if session_type == "wayland":
        return "wayland"
    if session_type == "x11":
        return "x11"
    if os.environ.get("WAYLAND_DISPLAY"):
        return "wayland"
    if os.environ.get("DISPLAY"):
        return "x11"
    return "unknown"


def detect_desktop() -> str:
    """Detect the desktop environment."""
    return os.environ.get("XDG_CURRENT_DESKTOP", "unknown")


def check_tool(name: str) -> bool:
    """Check if a CLI tool is available."""
    try:
        subprocess.run(
            ["which", name], capture_output=True, check=True, timeout=3
        )
        return True
    except (subprocess.CalledProcessError, FileNotFoundError):
        return False


# ---- Session Discovery ----


def discover_sessions() -> list[SessionInfo]:
    """Read ~/.claude/sessions/*.json to find all registered sessions."""
    sessions = []
    if not SESSIONS_DIR.exists():
        return sessions

    for session_file in SESSIONS_DIR.glob("*.json"):
        try:
            data = json.loads(session_file.read_text(encoding="utf-8"))
            session = SessionInfo(
                pid=data.get("pid", 0),
                session_id=data.get("sessionId", ""),
                cwd=data.get("cwd", ""),
                started_at=data.get("startedAt", 0),
            )
            sessions.append(session)
        except (json.JSONDecodeError, OSError) as exc:
            print(f"Warning: could not read {session_file}: {exc}", file=sys.stderr)

    return sessions


def validate_pid(pid: int) -> bool:
    """Check if a process with the given PID is alive and is Claude."""
    try:
        import psutil

        if not psutil.pid_exists(pid):
            return False
        proc = psutil.Process(pid)
        return "claude" in proc.name().lower()
    except Exception:
        return False


def walk_process_chain(pid: int) -> list[str]:
    """Walk the parent process chain from PID to root."""
    import psutil

    chain = []
    try:
        current = psutil.Process(pid)
        while current:
            chain.append(f"{current.name()} (PID {current.pid})")
            current = current.parent()
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        pass
    return chain


# ---- Container Detection ----

_TERMINAL_NAMES = {
    "gnome-terminal-server",
    "konsole",
    "xfce4-terminal",
    "alacritty",
    "kitty",
    "wezterm-gui",
    "terminator",
    "tilix",
    "xterm",
    "urxvt",
    "st",
    "foot",
    "ghostty",
}


def detect_container(pid: int) -> ContainerInfo:
    """Walk the parent process chain to identify the containing application."""
    import psutil

    container = ContainerInfo()
    try:
        claude_proc = psutil.Process(pid)
        current = claude_proc.parent()

        while current:
            name = current.name().lower()

            if "code" in name and name != "code":
                # VS Code on Linux is typically "code" binary
                pass
            if name == "code" or name.startswith("code-"):
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "VSCode"
                break

            if name in _TERMINAL_NAMES:
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "Terminal"
                break

            if name == "screen":
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "Screen"
                try:
                    current = current.parent()
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    break
                continue

            if name == "tmux: server" or name.startswith("tmux"):
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "Terminal"
                break

            try:
                current = current.parent()
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

        # Fallback: check TERM_PROGRAM env var
        if container.container_type == "Unknown":
            try:
                env = claude_proc.parent().environ()
                term_prog = env.get("TERM_PROGRAM", "").lower()
                del env  # drop full environment from memory
                if term_prog == "vscode":
                    container.container_type = "VSCode"
                elif term_prog:
                    container.container_type = "Terminal"
                    container.process_name = term_prog
            except (psutil.AccessDenied, psutil.NoSuchProcess, AttributeError):
                pass

    except (psutil.NoSuchProcess, psutil.AccessDenied):
        pass

    return container


# ---- Window Matching: Multiple Approaches ----


def list_windows_xdotool() -> list[WindowInfo]:
    """List windows using xdotool (X11 / XWayland)."""
    windows = []
    try:
        result = subprocess.run(
            ["xdotool", "search", "--name", ""],
            capture_output=True,
            text=True,
            timeout=5,
        )
        for line in result.stdout.strip().splitlines():
            wid = int(line.strip())
            info = WindowInfo(window_id=wid)
            # Get PID
            try:
                r = subprocess.run(
                    ["xdotool", "getwindowpid", str(wid)],
                    capture_output=True,
                    text=True,
                    timeout=3,
                )
                if r.returncode == 0 and r.stdout.strip():
                    info.pid = int(r.stdout.strip())
            except (subprocess.CalledProcessError, ValueError):
                pass
            # Get title
            try:
                r = subprocess.run(
                    ["xdotool", "getwindowname", str(wid)],
                    capture_output=True,
                    text=True,
                    timeout=3,
                )
                if r.returncode == 0:
                    info.title = r.stdout.strip()
            except subprocess.CalledProcessError:
                pass
            windows.append(info)
    except FileNotFoundError:
        print("  xdotool not installed", file=sys.stderr)
    except subprocess.TimeoutExpired:
        print("  xdotool timed out", file=sys.stderr)
    return windows


def list_windows_wmctrl() -> list[WindowInfo]:
    """List windows using wmctrl (X11 / XWayland)."""
    windows = []
    try:
        result = subprocess.run(
            ["wmctrl", "-l", "-p"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        for line in result.stdout.strip().splitlines():
            parts = line.split(None, 4)
            if len(parts) >= 5:
                wid = int(parts[0], 16)
                pid = int(parts[2])
                title = parts[4] if len(parts) > 4 else ""
                windows.append(WindowInfo(window_id=wid, pid=pid, title=title))
    except FileNotFoundError:
        print("  wmctrl not installed", file=sys.stderr)
    except subprocess.TimeoutExpired:
        print("  wmctrl timed out", file=sys.stderr)
    return windows


def list_windows_gnome_dbus() -> list[WindowInfo]:
    """List windows using GNOME Shell D-Bus eval (requires unsafe-mode).

    NOTE: Blocked on GNOME 45+ by default. Kept for reference only.
    Use list_windows_window_calls() instead.
    """
    windows = []
    js_code = (
        "global.get_window_actors().map(a => {"
        " let w = a.get_meta_window();"
        " return JSON.stringify({pid: w.get_pid(), title: w.get_title(), id: w.get_id()});"
        "}).join('\\n')"
    )
    try:
        result = subprocess.run(
            [
                "gdbus",
                "call",
                "--session",
                "--dest",
                "org.gnome.Shell",
                "--object-path",
                "/org/gnome/Shell",
                "--method",
                "org.gnome.Shell.Eval",
                js_code,
            ],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode == 0 and result.stdout.strip():
            raw = result.stdout.strip()
            if "'," in raw or "')" in raw:
                start = raw.index("'") + 1
                end = raw.rindex("'")
                data_str = raw[start:end]
                for line in data_str.split("\\n"):
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        obj = json.loads(line)
                        windows.append(
                            WindowInfo(
                                window_id=obj.get("id", 0),
                                pid=obj.get("pid", 0),
                                title=obj.get("title", ""),
                            )
                        )
                    except json.JSONDecodeError:
                        pass
        else:
            stderr_msg = result.stderr.strip()[:200] if result.stderr else ""
            print(f"  gdbus eval failed: rc={result.returncode} {stderr_msg}", file=sys.stderr)
    except FileNotFoundError:
        print("  gdbus not found", file=sys.stderr)
    except subprocess.TimeoutExpired:
        print("  gdbus timed out", file=sys.stderr)
    return windows


def list_windows_window_calls() -> list[WindowInfo]:
    """List windows using the window-calls GNOME Shell extension via D-Bus.

    This is the preferred method on GNOME/Wayland. Requires the
    window-calls extension: https://extensions.gnome.org/extension/4724/window-calls/

    D-Bus path: /org/gnome/Shell/Extensions/Windows
    Methods: List (enumerate), Activate (foreground by ID)
    """
    windows = []
    try:
        result = subprocess.run(
            [
                "gdbus",
                "call",
                "--session",
                "--dest",
                "org.gnome.Shell",
                "--object-path",
                "/org/gnome/Shell/Extensions/Windows",
                "--method",
                "org.gnome.Shell.Extensions.Windows.List",
            ],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode != 0:
            stderr_msg = result.stderr.strip()[:200] if result.stderr else ""
            print(f"  window-calls List failed: {stderr_msg}", file=sys.stderr)
            return windows

        raw = result.stdout.strip()
        # gdbus wraps output as ('json_string',)
        if raw.startswith("('") and raw.endswith("',)"):
            json_str = raw[2:-3]
        elif raw.startswith("('") and raw.endswith("')"):
            json_str = raw[2:-2]
        else:
            print(f"  unexpected gdbus output format: {raw[:100]}", file=sys.stderr)
            return windows

        for obj in json.loads(json_str):
            windows.append(
                WindowInfo(
                    window_id=obj.get("id", 0),
                    pid=obj.get("pid", 0),
                    title=obj.get("title", ""),
                    wm_class=obj.get("wm_class", ""),
                )
            )
    except FileNotFoundError:
        print("  gdbus not found", file=sys.stderr)
    except subprocess.TimeoutExpired:
        print("  window-calls List timed out", file=sys.stderr)
    except (json.JSONDecodeError, ValueError) as exc:
        print(f"  failed to parse window-calls output: {exc}", file=sys.stderr)
    return windows


def list_windows_xprop() -> list[WindowInfo]:
    """List windows using xprop + xwininfo (X11/XWayland fallback).

    Uses the root window's _NET_CLIENT_LIST to enumerate windows,
    then queries each for _NET_WM_PID and WM_NAME.
    """
    windows = []
    try:
        # Get client list from root window
        result = subprocess.run(
            ["xprop", "-root", "_NET_CLIENT_LIST"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode != 0:
            print("  xprop: _NET_CLIENT_LIST not available", file=sys.stderr)
            return windows

        # Parse window IDs from output like:
        # _NET_CLIENT_LIST(WINDOW): window id # 0x1234, 0x5678
        line = result.stdout.strip()
        if "#" not in line:
            return windows

        wid_str = line.split("#", 1)[1]
        wids = []
        for part in wid_str.split(","):
            part = part.strip()
            if part:
                try:
                    wids.append(int(part, 16))
                except ValueError:
                    pass

        for wid in wids:
            info = WindowInfo(window_id=wid)
            # Get PID
            try:
                r = subprocess.run(
                    ["xprop", "-id", str(wid), "_NET_WM_PID"],
                    capture_output=True,
                    text=True,
                    timeout=3,
                )
                if "=" in r.stdout:
                    info.pid = int(r.stdout.split("=")[1].strip())
            except (subprocess.CalledProcessError, ValueError, IndexError):
                pass
            # Get title
            try:
                r = subprocess.run(
                    ["xprop", "-id", str(wid), "WM_NAME"],
                    capture_output=True,
                    text=True,
                    timeout=3,
                )
                if "=" in r.stdout:
                    # WM_NAME(UTF8_STRING) = "title here"
                    title_part = r.stdout.split("=", 1)[1].strip()
                    info.title = title_part.strip('"')
            except (subprocess.CalledProcessError, ValueError, IndexError):
                pass
            windows.append(info)
    except FileNotFoundError:
        print("  xprop not found", file=sys.stderr)
    except subprocess.TimeoutExpired:
        print("  xprop timed out", file=sys.stderr)
    return windows


def match_window_to_container(
    container: ContainerInfo, windows: list[WindowInfo], cwd: str
) -> ContainerInfo:
    """Match a container process to a window from the enumerated list."""
    if container.process_pid == 0:
        return container

    import psutil

    # Collect all PIDs in the container's process tree
    target_pids = {container.process_pid}
    try:
        proc = psutil.Process(container.process_pid)
        for child in proc.children(recursive=True):
            target_pids.add(child.pid)
        # Also walk up to find the top-level process
        parent = proc.parent()
        if parent and parent.name().lower() == container.process_name.lower():
            target_pids.add(parent.pid)
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        pass

    # Find windows owned by any PID in the tree
    candidates = [w for w in windows if w.pid in target_pids]

    if not candidates:
        # Broader search: any window whose PID is in the tree
        return container

    # For VS Code, prefer window title matching the CWD folder name
    folder_name = Path(cwd).name.lower()
    for w in candidates:
        if folder_name in w.title.lower():
            container.window_id = w.window_id
            container.window_title = w.title
            return container

    # Fallback: first visible window
    if candidates:
        container.window_id = candidates[0].window_id
        container.window_title = candidates[0].title

    return container


# ---- Foreground ----


def foreground_window_xdotool(window_id: int) -> bool:
    """Foreground using xdotool (X11/XWayland)."""
    try:
        subprocess.run(
            ["xdotool", "windowactivate", str(window_id)],
            check=True,
            capture_output=True,
            timeout=3,
        )
        return True
    except (FileNotFoundError, subprocess.CalledProcessError, subprocess.TimeoutExpired) as exc:
        print(f"  xdotool foreground failed: {exc}", file=sys.stderr)
        return False


def foreground_window_gnome_dbus(window_id: int) -> bool:
    """Foreground using GNOME Shell D-Bus (Wayland-native).

    Uses the activate_window method on the Meta.Window object.
    """
    js_code = (
        f"let start = global.get_current_time();"
        f"global.get_window_actors().forEach(a => {{"
        f"  let w = a.get_meta_window();"
        f"  if (w.get_id() === {window_id}) w.activate(start);"
        f"}});"
    )
    try:
        result = subprocess.run(
            [
                "gdbus",
                "call",
                "--session",
                "--dest",
                "org.gnome.Shell",
                "--object-path",
                "/org/gnome/Shell",
                "--method",
                "org.gnome.Shell.Eval",
                js_code,
            ],
            capture_output=True,
            text=True,
            timeout=5,
        )
        return result.returncode == 0
    except (FileNotFoundError, subprocess.TimeoutExpired) as exc:
        print(f"  gdbus foreground failed: {exc}", file=sys.stderr)
        return False


def foreground_window_xprop(window_id: int) -> bool:
    """Foreground using xdotool with hex window ID from xprop."""
    return foreground_window_xdotool(window_id)


