def probe_dbus_interfaces() -> dict[str, str]:
    """Probe GNOME/freedesktop D-Bus interfaces for window management capabilities.

    Returns a dict of interface -> status describing what's available.
    """
    results = {}

    # 1. GNOME Shell Eval (needs unsafe mode on GNOME 45+)
    try:
        r = subprocess.run(
            [
                "gdbus", "call", "--session",
                "--dest", "org.gnome.Shell",
                "--object-path", "/org/gnome/Shell",
                "--method", "org.gnome.Shell.Eval",
                "1+1",
            ],
            capture_output=True, text=True, timeout=5,
        )
        if r.returncode == 0:
            success = r.stdout.strip().startswith("(true")
            results["gnome.Shell.Eval"] = "WORKS" if success else "BLOCKED (unsafe mode disabled)"
        else:
            results["gnome.Shell.Eval"] = f"FAILED rc={r.returncode}"
    except (FileNotFoundError, subprocess.TimeoutExpired) as exc:
        results["gnome.Shell.Eval"] = f"ERROR: {exc}"

    # 2. GNOME Shell FocusApp
    try:
        r = subprocess.run(
            [
                "gdbus", "call", "--session",
                "--dest", "org.gnome.Shell",
                "--object-path", "/org/gnome/Shell",
                "--method", "org.gnome.Shell.FocusApp",
                "org.gnome.Nautilus.desktop",
            ],
            capture_output=True, text=True, timeout=5,
        )
        if "AccessDenied" in (r.stderr or ""):
            results["gnome.Shell.FocusApp"] = "BLOCKED (AccessDenied)"
        elif r.returncode == 0:
            results["gnome.Shell.FocusApp"] = "WORKS"
        else:
            results["gnome.Shell.FocusApp"] = f"FAILED rc={r.returncode}"
    except (FileNotFoundError, subprocess.TimeoutExpired) as exc:
        results["gnome.Shell.FocusApp"] = f"ERROR: {exc}"

    # 3. XDG Desktop Portal — check available interfaces
    try:
        r = subprocess.run(
            [
                "gdbus", "introspect", "--session",
                "--dest", "org.freedesktop.portal.Desktop",
                "--object-path", "/org/freedesktop/portal/desktop",
            ],
            capture_output=True, text=True, timeout=5,
        )
        interfaces = []
        for line in r.stdout.splitlines():
            line = line.strip()
            if line.startswith("interface ") and "{" in line:
                iface = line.split()[1]
                if "freedesktop" in iface or "gnome" in iface:
                    interfaces.append(iface)
        results["xdg.portal.interfaces"] = ", ".join(interfaces) if interfaces else "none"
    except (FileNotFoundError, subprocess.TimeoutExpired) as exc:
        results["xdg.portal"] = f"ERROR: {exc}"

    # 4. GNOME Shell introspection — list available methods
    try:
        r = subprocess.run(
            [
                "gdbus", "introspect", "--session",
                "--dest", "org.gnome.Shell",
                "--object-path", "/org/gnome/Shell",
            ],
            capture_output=True, text=True, timeout=5,
        )
        methods = []
        for line in r.stdout.splitlines():
            line = line.strip()
            if line.startswith("Eval(") or line.startswith("Focus") or "Activate" in line:
                methods.append(line.split("(")[0])
        results["gnome.Shell.methods"] = ", ".join(methods) if methods else "see introspect"
    except (FileNotFoundError, subprocess.TimeoutExpired) as exc:
        results["gnome.Shell.introspect"] = f"ERROR: {exc}"

    # 5. Check if GNOME Shell extensions can help
    try:
        r = subprocess.run(
            ["gnome-extensions", "list", "--enabled"],
            capture_output=True, text=True, timeout=5,
        )
        if r.returncode == 0:
            extensions = [e.strip() for e in r.stdout.strip().splitlines() if e.strip()]
            results["gnome.extensions.enabled"] = ", ".join(extensions) if extensions else "none"
        else:
            results["gnome.extensions"] = "gnome-extensions command failed"
    except FileNotFoundError:
        results["gnome.extensions"] = "gnome-extensions not found"
    except subprocess.TimeoutExpired:
        results["gnome.extensions"] = "timed out"

    return results


def analyze_vscode_processes() -> dict[int, dict]:
    """Analyze VS Code process tree to map workspace windows.

    VS Code runs multiple processes:
    - Main process (parent is systemd/init)
    - Renderer processes (--type=renderer) — one per window
    - GPU, utility, crashpad helpers

    The renderer cmdline contains --vscode-window-config with a path
    that includes the workspace folder. The PID of the renderer owns
    the actual window.
    """
    import psutil

    results = {}

    # Find all VS Code processes
    code_procs = []
    for proc in psutil.process_iter(["pid", "name", "ppid"]):
        try:
            if proc.info["name"] and proc.info["name"].lower() in ("code", "code-oss"):
                code_procs.append(proc)
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass

    if not code_procs:
        return results

    for proc in code_procs:
        try:
            cmdline = proc.cmdline()
            cmdline_str = " ".join(cmdline)
            info = {
                "pid": proc.pid,
                "ppid": proc.ppid(),
                "name": proc.name(),
                "type": "unknown",
                "cmdline_summary": cmdline_str[:200],
            }

            # Classify process type from --type= flag
            for arg in cmdline:
                if arg.startswith("--type="):
                    info["type"] = arg.split("=")[1]
                    break
            else:
                # No --type flag = main process or window host
                if any("--folder-uri" in a or "--file-uri" in a for a in cmdline):
                    info["type"] = "window-host"
                else:
                    info["type"] = "main"

            # Extract workspace info from various cmdline patterns
            for i, arg in enumerate(cmdline):
                if arg == "--folder-uri" and i + 1 < len(cmdline):
                    info["folder_uri"] = cmdline[i + 1]
                if arg.startswith("--folder-uri="):
                    info["folder_uri"] = arg.split("=", 1)[1]
                if "--vscode-window-config" in arg:
                    info["window_config"] = arg[:200]

            # Check environment for workspace hints
            try:
                env = proc.environ()
                if "VSCODE_PID" in env:
                    info["vscode_pid"] = env["VSCODE_PID"]
                if "VSCODE_CWD" in env:
                    info["vscode_cwd"] = env["VSCODE_CWD"]
                del env
            except (psutil.AccessDenied, psutil.NoSuchProcess):
                pass

            results[proc.pid] = info
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass

    return results


def find_vscode_window_for_cwd(cwd: str) -> dict:
    """Find the specific VS Code window process that has a given CWD open.

    Returns info about the matching process, or empty dict if not found.
    """
    vscode_procs = analyze_vscode_processes()
    folder_name = Path(cwd).name

    # Strategy 1: match by --folder-uri in renderer/window-host cmdline
    for pid, info in vscode_procs.items():
        folder_uri = info.get("folder_uri", "")
        if folder_uri and (cwd in folder_uri or folder_name in folder_uri):
            info["match_method"] = "folder_uri"
            return info

    # Strategy 2: match by VSCODE_CWD environment
    for pid, info in vscode_procs.items():
        vscode_cwd = info.get("vscode_cwd", "")
        if vscode_cwd and cwd == vscode_cwd:
            info["match_method"] = "vscode_cwd"
            return info

    # Strategy 3: match by window config path containing folder name
    for pid, info in vscode_procs.items():
        config = info.get("window_config", "")
        if config and folder_name in config:
            info["match_method"] = "window_config"
            return info

    return {}


def probe_activation_methods(
    container: ContainerInfo, cwd: str
) -> dict[str, str]:
    """Test various methods to activate/foreground a specific container window.

    Only tests non-destructive probes. Returns status for each method.
    """
    results = {}

    if container.process_pid == 0:
        results["skip"] = "no container PID"
        return results

    # 1. VS Code CLI: `code /path` activates the window with that folder open
    if container.container_type == "VSCode":
        try:
            # First check if code CLI is available
            r = subprocess.run(
                ["which", "code"],
                capture_output=True, text=True, timeout=3,
            )
            if r.returncode == 0:
                results["code CLI"] = f"available at {r.stdout.strip()}"
                results["code /path (theory)"] = (
                    f"`code {cwd}` should activate the window with this folder. "
                    f"Uses --reuse-window semantics."
                )
            else:
                results["code CLI"] = "not in PATH"
        except (FileNotFoundError, subprocess.TimeoutExpired):
            results["code CLI"] = "check failed"

    # 2. gtk-launch: activates the application generically (not window-specific)
    app_id = ""
    if container.container_type == "VSCode":
        app_id = "code.desktop"
    elif container.container_type == "Terminal":
        app_id = "org.gnome.Terminal.desktop"

    if app_id:
        results[f"gtk-launch {app_id}"] = "activates app generically (NOT window-specific)"

    # 3. xdotool (if installed)
    if container.window_id:
        try:
            r = subprocess.run(
                ["xdotool", "windowactivate", str(container.window_id)],
                capture_output=True, text=True, timeout=3,
            )
            results["xdotool windowactivate"] = (
                "WORKS" if r.returncode == 0 else f"FAILED rc={r.returncode}"
            )
        except FileNotFoundError:
            results["xdotool"] = "not installed"
        except subprocess.TimeoutExpired:
            results["xdotool"] = "timed out"

    # 4. wmctrl -ia (if available)
    if container.window_id:
        try:
            r = subprocess.run(
                ["wmctrl", "-ia", str(container.window_id)],
                capture_output=True, text=True, timeout=3,
            )
            results["wmctrl -ia"] = "WORKS" if r.returncode == 0 else f"FAILED rc={r.returncode}"
        except FileNotFoundError:
            results["wmctrl"] = "not installed"
        except subprocess.TimeoutExpired:
            results["wmctrl"] = "timed out"

    # 5. xdg-activation (Wayland protocol)
    results["xdg-activation"] = "requires app cooperation, no standalone CLI"

    return results


# ---- Main ----


def main():
    parser = argparse.ArgumentParser(
        description="Linux session detection and window matching diagnostic"
    )
    parser.add_argument("--json", action="store_true", help="Output as JSON")
    parser.add_argument("--verbose", action="store_true", help="Show extra details")
    args = parser.parse_args()

    print("=== Environment ===")
    display_server = detect_display_server()
    desktop = detect_desktop()
    print(f"  Display server: {display_server}")
    print(f"  Desktop: {desktop}")
    print(f"  DISPLAY: {os.environ.get('DISPLAY', '(not set)')}")
    print(f"  WAYLAND_DISPLAY: {os.environ.get('WAYLAND_DISPLAY', '(not set)')}")
    print()

    tools = ["xdotool", "wmctrl", "xprop", "xwininfo", "gdbus", "gtk-launch", "gnome-extensions"]
    print("=== Available Tools ===")
    for tool in tools:
        available = check_tool(tool)
        print(f"  {tool}: {'YES' if available else 'no'}")
    print()

    print("=== D-Bus Interface Probes ===")
    dbus_probes = probe_dbus_interfaces()
    for iface, status in dbus_probes.items():
        print(f"  {iface}: {status}")
    print()

    print("=== Window Enumeration Methods ===")

    print("\n--- Method 1: xprop (_NET_CLIENT_LIST) ---")
    xprop_windows = list_windows_xprop()
    print(f"  Found {len(xprop_windows)} windows")
    for w in xprop_windows[:10]:
        print(f"    id=0x{w.window_id:x} pid={w.pid} title={w.title!r}")

    print("\n--- Method 2: xdotool ---")
    xdotool_windows = list_windows_xdotool()
    print(f"  Found {len(xdotool_windows)} windows")
    for w in xdotool_windows[:10]:
        print(f"    id=0x{w.window_id:x} pid={w.pid} title={w.title!r}")

    print("\n--- Method 3: wmctrl ---")
    wmctrl_windows = list_windows_wmctrl()
    print(f"  Found {len(wmctrl_windows)} windows")
    for w in wmctrl_windows[:10]:
        print(f"    id=0x{w.window_id:x} pid={w.pid} title={w.title!r}")

    print("\n--- Method 4: GNOME Shell D-Bus (Eval, requires unsafe-mode) ---")
    dbus_windows = list_windows_gnome_dbus()
    print(f"  Found {len(dbus_windows)} windows")
    for w in dbus_windows[:10]:
        print(f"    id={w.window_id} pid={w.pid} title={w.title!r}")

    print("\n--- Method 5: window-calls GNOME extension (PREFERRED) ---")
    wc_windows = list_windows_window_calls()
    print(f"  Found {len(wc_windows)} windows")
    for w in wc_windows[:10]:
        print(f"    id={w.window_id} pid={w.pid} class={w.wm_class!r} title={w.title!r}")

    # Pick the best window list — prefer window-calls extension
    best_windows = wc_windows or xprop_windows or dbus_windows or xdotool_windows or wmctrl_windows
    best_method = (
        "window-calls"
        if wc_windows
        else "xprop"
        if xprop_windows
        else "gdbus-eval"
        if dbus_windows
        else "xdotool"
        if xdotool_windows
        else "wmctrl"
        if wmctrl_windows
        else "none"
    )
    print(f"\n  Best method: {best_method} ({len(best_windows)} windows)")

    print("\n=== Claude Sessions ===")
    sessions = discover_sessions()

    if not sessions:
        print("  No sessions found in ~/.claude/sessions/")
        return

    for session in sessions:
        session.pid_alive = validate_pid(session.pid)
        if session.pid_alive:
            session.process_chain = walk_process_chain(session.pid)
            session.container = detect_container(session.pid)
            session.container = match_window_to_container(
                session.container, best_windows, session.cwd
            )

    if args.json:
        output = [asdict(s) for s in sessions]
        print(json.dumps(output, indent=2))
    else:
        for session in sessions:
            alive = "ALIVE" if session.pid_alive else "DEAD"
            print(f"\n  Session: {session.session_id[:16]}...")
            print(f"    PID:       {session.pid} ({alive})")
            print(f"    CWD:       {session.cwd}")
            if session.container:
                c = session.container
                print(f"    Container: {c.container_type} ({c.process_name})")
                if c.window_id:
                    wid_hex = f"0x{c.window_id:x}" if c.window_id > 0xFF else str(c.window_id)
                    print(f"    Window:    {wid_hex} {c.window_title!r}")
            if args.verbose and session.process_chain:
                print(f"    Chain:     {' -> '.join(session.process_chain)}")

    # VS Code process analysis
    print("\n=== VS Code Process Analysis ===")
    vscode_procs = analyze_vscode_processes()
    if vscode_procs:
        for pid, info in sorted(vscode_procs.items()):
            ptype = info.get("type", "?")
            print(f"\n  PID {pid} [{ptype}]")
            if info.get("folder_uri"):
                print(f"    folder_uri: {info['folder_uri']}")
            if info.get("vscode_cwd"):
                print(f"    vscode_cwd: {info['vscode_cwd']}")
            if info.get("window_config"):
                print(f"    window_config: {info['window_config']}")
            if args.verbose:
                print(f"    cmdline: {info.get('cmdline_summary', '')}")
    else:
        print("  No VS Code processes found")

    # Window matching for each VS Code session
    print("\n=== VS Code Window Matching ===")
    for session in sessions:
        if session.pid_alive and session.container and session.container.container_type == "VSCode":
            match = find_vscode_window_for_cwd(session.cwd)
            if match:
                print(f"\n  CWD: {session.cwd}")
                print(f"    Matched PID: {match.get('pid')}")
                print(f"    Match method: {match.get('match_method')}")
                if match.get("folder_uri"):
                    print(f"    folder_uri: {match['folder_uri']}")
            else:
                print(f"\n  CWD: {session.cwd}")
                print(f"    NO MATCH FOUND")

    # Test activation methods on each unique container type
    print("\n=== Activation Method Probes ===")
    tested_types = set()
    for session in sessions:
        if not session.pid_alive or not session.container:
            continue
        ctype = session.container.container_type
        if ctype in tested_types:
            continue
        tested_types.add(ctype)
        print(f"\n  Testing activation for {ctype} "
              f"({session.container.process_name}, PID {session.container.process_pid}):")
        probes = probe_activation_methods(session.container, session.cwd)
        for method, status in probes.items():
            print(f"    {method}: {status}")
    if not tested_types:
        print("  No live sessions with containers to test")


if __name__ == "__main__":
    main()
